INSERT INTO skill_definitions (slug, display_name, description) VALUES
('modeling_basic_posing', 'Basic Posing', 'Learn angles, expressions, and body language for the camera.'),
('modeling_professional_posing', 'Professional Posing', 'Deliver versatile poses that convey mood, brand, and editorial vision.'),
('modeling_mastery_posing', 'Posing Mastery', 'Every frame is iconic — your poses define campaigns and eras.'),
('modeling_basic_runway', 'Basic Runway', 'Walk with confidence, maintain pace, and hit your mark.'),
('modeling_professional_runway', 'Professional Runway', 'Command the catwalk with signature walks and dramatic turns.'),
('modeling_mastery_runway', 'Runway Mastery', 'Your runway presence stops shows and trends globally.'),
('modeling_basic_camera', 'Basic Camera Work', 'Stay natural, follow direction, and avoid common beginner mistakes.'),
('modeling_professional_camera', 'Professional Camera Presence', 'Engage the lens with magnetism and convey emotion effortlessly.'),
('modeling_mastery_camera', 'Camera Mastery', 'The camera loves you — every shot is cover-worthy.'),
('modeling_basic_commercial', 'Basic Commercial', 'Smile, look approachable, and sell everyday products.'),
('modeling_professional_commercial', 'Professional Commercial', 'Land national campaigns and bring brand stories to life.'),
('modeling_mastery_commercial', 'Commercial Mastery', 'You are the face of the biggest brands on earth.'),
('modeling_basic_editorial', 'Basic Editorial', 'Interpret artistic concepts and work with creative teams.'),
('modeling_professional_editorial', 'Professional Editorial', 'Bring avant-garde visions to life for top magazines.'),
('modeling_mastery_editorial', 'Editorial Mastery', 'Your editorial work is art — museum-worthy and genre-defining.'),
('modeling_basic_brand', 'Basic Brand Work', 'Represent brands authentically and build early partnerships.'),
('modeling_professional_brand', 'Professional Brand Strategy', 'Negotiate multi-campaign deals and manage brand relationships.'),
('modeling_mastery_brand', 'Brand Empire', 'Launch your own brand or become the lifetime face of a fashion house.'),
('fashion_basic_fundamentals', 'Basic Fashion Knowledge', 'Study fashion history, silhouettes, and style principles.'),
('fashion_professional_fundamentals', 'Professional Fashion Theory', 'Analyze trends, forecast seasons, and develop design philosophy.'),
('fashion_mastery_fundamentals', 'Fashion Mastery', 'You set the trends — your vision shapes the industry.'),
('fashion_basic_textiles', 'Basic Textiles', 'Identify fabrics, understand weaves, and learn material properties.'),
('fashion_professional_textiles', 'Professional Materials', 'Source premium fabrics and work with exotic textiles.'),
('fashion_mastery_textiles', 'Textile Mastery', 'Develop proprietary fabrics and revolutionize material science in fashion.'),
('fashion_basic_patterns', 'Basic Patterns', 'Draft basic patterns, take measurements, and create templates.'),
('fashion_professional_patterns', 'Professional Pattern Design', 'Engineer complex patterns for couture and ready-to-wear.'),
('fashion_mastery_patterns', 'Pattern Mastery', 'Your pattern innovations redefine garment construction.'),
('fashion_basic_styling', 'Basic Styling', 'Coordinate outfits, understand color theory, and build mood boards.'),
('fashion_professional_styling', 'Professional Aesthetics', 'Curate collections with cohesive visual narratives.'),
('fashion_mastery_styling', 'Style Mastery', 'Your aesthetic is instantly recognizable and globally influential.'),
('fashion_basic_business', 'Basic Fashion Business', 'Understand fashion supply chains, pricing, and retail basics.'),
('fashion_professional_business', 'Professional Fashion Management', 'Manage production runs, distribution, and fashion house operations.'),
('fashion_mastery_business', 'Fashion Empire', 'Build a global fashion empire with multiple revenue streams.'),
('clothing_basic_construction', 'Basic Construction', 'Sew seams, set zippers, and assemble basic garments.'),
('clothing_professional_construction', 'Professional Garment Making', 'Construct tailored pieces with precision finishing and quality control.'),
('clothing_mastery_construction', 'Construction Mastery', 'Your construction quality rivals the finest ateliers in the world.'),
('clothing_basic_branding', 'Basic Clothing Brand', 'Create a brand identity, logo, and positioning strategy.'),
('clothing_professional_branding', 'Professional Brand Identity', 'Build brand recognition through marketing, collabs, and storytelling.'),
('clothing_mastery_branding', 'Brand Legend', 'Your brand is a cultural icon — worn by celebrities and revered globally.'),
('clothing_basic_genre_aesthetics', 'Basic Genre Style', 'Study the visual identities of music genres and subcultures.'),
('clothing_professional_genre_aesthetics', 'Professional Genre Fashion', 'Design genre-authentic clothing that resonates with fan communities.'),
('clothing_mastery_genre_aesthetics', 'Genre Fashion Mastery', 'Your designs define the look of entire music movements.'),
('clothing_basic_retail', 'Basic Retail', 'Set up a shop, price items, and manage basic inventory.'),
('clothing_professional_retail', 'Professional Shop Management', 'Optimize sales, manage staff, and run multi-location retail.'),
('clothing_mastery_retail', 'Retail Empire', 'Your retail operation is a global chain with flagship stores worldwide.')
